import socket
from microcoapy import MicroCoAP

def handle_request(payload, path):
    if path == b"/sensors/temp":
        return "25.0C".encode()
    elif path == b"/actuators/light":
        if payload.decode() == "ON":
            # Turn light on
            return "Light turned ON".encode()
        elif payload.decode() == "OFF":
            # Turn light off
            return "Light turned OFF".encode()
    return None

def main():
    server = MicroCoAP("0.0.0.0", 5683)
    server.register_resource("/sensors/temp", handle_request)
    server.register_resource("/actuators/light", handle_request)

    while True:
        try:
            server.poll(2000)  # Poll for incoming requests
        except KeyboardInterrupt:
            break

if __name__ == "__main__":
    main()